xecutorTimerLockTimeInMillis(300000); // 5 minutes\n        \n        // Expired jobs cleanup\n        config.setAsyncExecutorResetExpiredJobsInterval(60000); // 1 minute\n        config.setAsyncExecutorResetExpiredJobsPageSize(3);\n        \n        return config;\n    }\n}\n"})}),"\n",(0,r.jsxs)(n.p,{children:[(0,r.jsx)(n.strong,{children:"Source:"})," ",(0,r.jsx)(n.code,{children:"ProcessEngineConfigurationImpl.java"})]}),"\n",(0,r.jsx)(n.h2,{id:"job-execution-flow",children:"Job Execution Flow"}),"\n",(0,r.jsx)(n.h3,{id:"1-job-creation",children:"1. Job Creation"}),"\n",(0,r.jsx)(n.pre,{children:(0,r.jsx)(n.code,{className:"language-xml",children:'\x3c!-- Async service task creates executable job --\x3e\n<serviceTask id="asyncTask" name="Async Processing" \n             activiti:class="com.example.AsyncProcessor"\n             activiti:async="true"/>\n\n\x3c!-- Timer event creates timer job --\x3e\n<intermediateCatchEvent id="timerEvent">\n  <timerEventDefinition>\n    <timeDuration>PT1H</timeDuration>\n  </timerEventDefinition>\n</intermediateCatchEvent>\n\n\x3c!-- Message event creates message job --\x3e\n<intermediateCatchEvent id="messageEvent">\n  <messageEventDefinition messageRef="myMessage"/>\n</intermediateCatchEvent>\n'})}),"\n",(0,r.jsx)(n.h3,{id:"2-job-acquisition",children:"2. Job Acquisition"}),"\n",(0,r.jsx)(n.pre,{children:(0,r.jsx)(n.code,{children:"Async Executor Acquisition Loop:\n\n1. Acquire database lock (prevents multiple executors)\n2. Query for due jobs:\n   - execution_time <= now\n   - retries > 0 or not yet failed\n   - lock_expiry < now or not locked\n3. Lock acquired jobs:\n   - Set LOCK_OWNER (executor ID)\n   - Set LOCK_EXPIRY (current time + lock duration)\n4. Assign to worker thread pool\n5. Release database lock\n6. Wait for configured interval\n7. Repeat\n"})}),"\n",(0,r.jsxs)(n.p,{children:[(0,r.jsx)(n.strong,{children:"Source:"})," ",(0,r.jsx)(n.code,{children:"DefaultAsyncJobExecutor.java"})]}),"\n",(0,r.jsx)(n.h3,{id:"3-jo